\*sigh\* For the record, `und-u-va-posix` _is_ normalization aware, which makes it explicitly different from `LC_COLLATE=POSIX` (which ignore normalization, both on macOS and Linux).

```go
package main

// #include <locale.h>
// #include <stdlib.h>
// #include <string.h>
import "C"

import (
	"fmt"
	"sort"
	"strings"
	"unsafe"

	"golang.org/x/text/collate"
	"golang.org/x/text/language"
	"golang.org/x/text/unicode/norm"
)

var inputStrings = []string{
	"baa",
	"baá",
	"báa",
	"bab",
	"báb",
	"bac",
	"bác",
	"bač",
	"báč",
}

type input struct {
	value string
	norm  norm.Form
}

func newInput(s string, norm norm.Form) input {
	return input{
		value: norm.String(s),
		norm:  norm,
	}
}

var formName = map[norm.Form]string{
	norm.NFC: "NFC",
	norm.NFD: "NFD",
}

func printResults(name string, vals []input) {
	fmt.Printf("%s\n", name)
	fmt.Printf("%s\n", strings.Repeat("=", len(name)))
	fmt.Printf("%s\t%s\t%-14s\t%-14s\t%s\n", "Text", "Norm", "Raw", "NFC", "NFD")
	for _, v := range vals {
		fmt.Printf("%s\t%s\t%-14x\t%-14x\t%x\n", v.value, formName[v.norm], []byte(v.value), norm.NFC.Bytes([]byte(v.value)), norm.NFD.Bytes([]byte(v.value)))
	}

}

type inputsLister []input

func (il inputsLister) Len() int {
	return len(il)
}

func (il inputsLister) Swap(i, j int) {
	il[i], il[j] = il[j], il[i]
}

func (il inputsLister) Bytes(i int) []byte {
	return []byte(il[i].value)
}

func strcoll(a, b string) int {
	ca := C.CString(a)
	defer C.free(unsafe.Pointer(ca))
	cb := C.CString(b)
	defer C.free(unsafe.Pointer(cb))

	return int(C.strcoll(ca, cb))
}

func main() {
	vals := []input{}
	for _, s := range inputStrings {
		vals = append(vals, newInput(s, norm.NFC), newInput(s, norm.NFD))
	}

	sort.Slice(vals, func(i, j int) bool { return strings.ToLower(vals[i].value) < strings.ToLower(vals[j].value) })
	printResults("string < on strings.ToLower", vals)

	lang, err := language.Parse("und-u-va-posix")
	if err != nil {
		panic(err.Error())
	}
	collator := collate.New(lang, collate.IgnoreCase, collate.IgnoreWidth)
	collator.Sort(inputsLister(vals))
	printResults("collate(und-u-va-posix, IgnoreCase)", vals)

	empty := C.CString("")
	C.setlocale(C.LC_ALL, empty)
	check := C.setlocale(C.LC_ALL, nil)
	sort.Slice(vals, func(i, j int) bool { return strcoll(vals[i].value, vals[j].value) < 0 })
	printResults("strcoll "+C.GoString(check), vals)
}
```
